INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2937d65c-c86b-4543-b5f6-35ed0dc848f3',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi + IPFS — Resolving On-Chain CIDs Without Breaking NFT Metadata$escape$,
  $escape$IPFS uses content addressing: a CID is a cryptographic hash of the content itself, so `ipfs://bafkreigh2akiscaild...` always resolves to identical bytes regardless of which peer serves them. When wagmi's `useReadContract` reads `tokenURI` from an ERC-721, it typically returns an IPFS URI — either CIDv0 (`Qm...`, base58 SHA2-256) or CIDv1 (`baf...`, base32 multibase). Browsers don't speak the `ipfs://` scheme natively, so you must rewrite to an HTTP gateway before passing to `fetch` or an `<img>` tag.

The DHT (Distributed Hash Table) is how IPFS nodes discover which peers hold a given CID — it's a lookup layer, not a guarantee of availability. Pinning is that guarantee: without an explicit pin, nodes garbage-collect unpinned content. For production, use Pinata or Web3.Storage to pin NFT metadata CIDs.

IPFS ≠ Filecoin: IPFS is the content-routing protocol; Filecoin is a separate incentive layer that pays storage providers to hold pinned CIDs under cryptographic proof-of-storage deals. An unpinned CID on IPFS can vanish; a Filecoin deal gives you verifiable persistence. Always validate the CID prefix in wagmi hooks before resolving — a malformed URI silently returns `undefined` from `useReadContract`.$escape$,
  $escape$import { useReadContract } from 'wagmi'
import { erc721Abi } from 'viem'

const toGatewayUrl = (uri: string): string =>
  uri.startsWith('ipfs://')
    ? `https://ipfs.io/ipfs/${uri.slice(7)}`
    : uri

export function useNFTMetadataUrl(
  address: `0x${string}`,
  tokenId: bigint
) {
  const { data: tokenUri } = useReadContract({
    address,
    abi: erc721Abi,
    functionName: 'tokenURI',
    args: [tokenId],
  })
  return tokenUri ? toGatewayUrl(tokenUri) : null
}$escape$,
  $escape$typescript$escape$,
