INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b4262e46-7afc-4eae-9ac8-74597a311647',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi Multicall — Batch Contract Reads with useReadContracts$escape$,
  $escape$Every separate `useReadContract` call fires its own `eth_call` RPC request. At scale — think displaying token balances, allowances, and staking positions simultaneously — this hammers your RPC provider and inflates latency. wagmi's `useReadContracts` solves this by batching all reads through the Multicall3 contract in a single `eth_call`.

Pass an array of `contracts` configs — each with `address`, `abi`, and `functionName` — and wagmi routes them through Multicall3 automatically when the chain supports it (virtually all EVM chains do). Results come back as a typed array of `{ result, status }` objects, so you handle individual failures without losing the entire batch.

Set `allowFailure: false` if you need strict all-or-nothing semantics — wagmi will throw if any call reverts. Leave it `true` (the default) for resilient UIs that degrade gracefully per-call. Combine with `multicallAddress` override when targeting chains with a custom Multicall3 deployment. The batching is automatic — no manual ABI encoding needed.$escape$,
  $escape$import { useReadContracts } from 'wagmi'
import { erc20Abi } from 'viem'

const tokenContract = { address: '0xA0b8...', abi: erc20Abi } as const

function TokenStats({ account }: { account: `0x${string}` }) {
  const { data } = useReadContracts({
    allowFailure: false,
    contracts: [
      { ...tokenContract, functionName: 'balanceOf', args: [account] },
      { ...tokenContract, functionName: 'totalSupply' },
      { ...tokenContract, functionName: 'decimals' },
    ],
  })

  const [balance, totalSupply, decimals] = data ?? []
  return <div>{balance?.toString()}</div>
}$escape$,
