INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '24d59ee7-a0cb-48b1-b63e-6bce4983c523',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi — Handling Pending States, Failed Transactions, and Gas Errors Like a Pro$escape$,
  $escape$wagmi's `useWriteContract` and `useWaitForTransactionReceipt` give you fine-grained control over every UX state in a transaction lifecycle. `useWriteContract` exposes `isPending` (wallet prompt open) and `isError` with a typed `error` — check `error.cause` for `UserRejectedRequestError` to distinguish user cancellations from real failures. Once you have a `hash`, pass it to `useWaitForTransactionReceipt` to track `isLoading` (mining) vs `isSuccess` vs `isError` (reverted on-chain). For gas estimation failures, `useEstimateGas` throws a `ContractFunctionExecutionError` before the wallet even opens — catch this to show inline warnings instead of letting the wallet display a cryptic error. Combine `useSimulateContract` before calling `writeContract`: if simulation fails, the button stays disabled and you surface the revert reason directly from `error.cause.reason`. This pattern eliminates the three most common Web3 UX dead-ends: silent wallet rejections, confusing mining spinners, and surprise gas failures at signing time.$escape$,
  $escape$const { data: sim, error: simError } = useSimulateContract({ ...config });
const { writeContract, data: hash, isPending, error: writeError } = useWriteContract();
const { isLoading: isMining, isSuccess } = useWaitForTransactionReceipt({ hash });

const label = isPending ? 'Confirm in wallet…'
  : isMining   ? 'Mining…'
  : isSuccess  ? 'Done!'
  : 'Submit';

const rejectMsg = writeError?.cause instanceof UserRejectedRequestError
  ? 'You rejected the transaction.'
  : writeError?.shortMessage;

return (
  <button disabled={!sim || isPending || isMining} onClick={() => writeContract(sim!.request)}>
    {label}
  </button>
);
// simError?.cause?.reason surfaces revert reason before wallet opens$escape$,
  $escape$typescript$escape$,
