INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'efbfdbfd-44b0-4358-b4a9-f2bab316a5ea',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi's Transport Layer — ethers.js vs viem vs web3.js Migration Considerations$escape$,
  $escape$wagmi v2 dropped ethers.js entirely and is built on viem as its sole peer dependency. This isn't cosmetic — viem is tree-shakable, ships typed ABI encoding via `parseAbi`/`encodeAbiParameters`, and returns native BigInt instead of ethers' `BigNumber`. If you're migrating a wagmi v1 project, the breakage surfaces immediately in `useContractRead` → `useReadContract`, `usePrepareContractWrite` → `useSimulateContract`, and anywhere you passed ethers `Contract` instances or `providers`. Replace ethers utility calls with viem equivalents: `ethers.utils.formatEther` → `formatEther` from viem, `ethers.utils.parseUnits` → `parseUnits`. web3.js has no first-class integration path — wagmi never supported it natively, so a migration means rewriting all contract interaction logic to viem's `readContract`/`writeContract` primitives, which the wagmi hooks wrap internally. The upside: viem's strict TypeScript inference means your ABI types flow end-to-end through `useReadContract`'s `data` return without manual casting.$escape$,
  $escape$import { useReadContract } from 'wagmi'
import { parseAbi, formatEther } from 'viem'

const abi = parseAbi(['function balanceOf(address) view returns (uint256)'])

export function TokenBalance({ address }: { address: `0x${string}` }) {
  const { data: balance } = useReadContract({
    abi,
    address: '0x6B175474E89094C44Da98b954EedeAC495271d0f',
    functionName: 'balanceOf',
    args: [address],
  })

  // balance is typed as bigint — no BigNumber.from() needed
  return <p>{balance ? formatEther(balance) : '0'} DAI</p>
}$escape$,
  $escape$typescript$escape$,
