INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '02a05ccc-7768-4a8f-a11e-eee51ae9e8ee',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi Contract ABIs — Encoding, Decoding, and Typed Generation$escape$,
  $escape$ABIs (Application Binary Interfaces) define a contract's external surface — function names, argument types, return types, and event signatures. The EVM uses this schema to encode calldata (function selector + ABI-encoded args) and decode return data back into usable values.

In wagmi, every hook that touches a contract — `useReadContract`, `useWriteContract`, `useSimulateContract` — requires an ABI. Wagmi delegates the actual encoding and decoding to viem under the hood. The critical detail: always annotate your ABI `as const`. Without it, TypeScript widens the type to `string`, and wagmi can't infer `functionName` as a union of your contract's methods, narrow `args` to the correct tuple types, or type the return value — everything degrades to `unknown`.

For real projects, skip hand-authored ABIs entirely. Use `@wagmi/cli` with the `foundry` or `etherscan` plugin: `wagmi generate` outputs a `src/generated.ts` with `as const` ABIs and pre-built typed React hooks for every contract function. Your hooks stay in sync with deployments automatically, and you get zero-config type safety across the stack.

For manual encoding outside hooks — multicall payloads, raw transaction construction — reach for viem's `encodeFunctionData` and `decodeFunctionResult` directly.$escape$,
  $escape$import { useReadContract } from 'wagmi'

const erc20Abi = [
  {
    name: 'balanceOf',
    type: 'function',
    stateMutability: 'view',
    inputs: [{ name: 'account', type: 'address' }],
    outputs: [{ name: '', type: 'uint256' }],
  },
] as const // critical: enables full TypeScript inference in wagmi hooks

export function TokenBalance({ account }: { account: `0x${string}` }) {
  const { data: balance } = useReadContract({
    abi: erc20Abi,
    address: '0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48',
    functionName: 'balanceOf', // autocompleted from ABI union
    args: [account],           // typed as [`0x${string}`], not unknown[]
  })

  return <span>{balance?.toString() ?? '0'}</span>
}$escape$,
  $escape$typescript$escape$,
