INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '69897f06-d609-4e64-86c0-835edf173152',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi RPC Management — Fallback Providers, Rate Limits, and Picking Between Alchemy, Infura, and QuickNode$escape$,
  $escape$wagmi v2 delegates all transport logic to viem — so RPC management lives in your `createConfig` `transports` map, not in React hooks. The critical primitive is viem's `fallback()` transport, which chains multiple providers and automatically retries the next one on any network error or 429 rate limit response.

Alchemy is the default choice for most dApps: generous free tier (300M compute units/month), fast archive access, and reliable `eth_getLogs` with deep block range support. Infura works for simple reads but throttles aggressively on free plans and imposes stricter `eth_getLogs` depth limits. QuickNode shines for latency-sensitive workloads like real-time mempool watching over WebSocket, but costs more at scale.

Pass `rank: true` to `fallback()` to enable latency-based provider ranking — wagmi will automatically prefer the fastest responding RPC across requests. For WebSocket subscriptions (used by `useWatchContractEvent` and `useWatchBlocks`), configure a separate `webSocket()` transport alongside your `http()` fallback; `fallback()` supports mixed transport types. Each `http()` instance accepts `retryCount` and `retryDelay` to tune per-provider retry behavior before escalating down the fallback chain.$escape$,
  $escape$import { createConfig, http, webSocket } from 'wagmi'
import { mainnet } from 'wagmi/chains'
import { fallback } from 'viem'

export const config = createConfig({
  chains: [mainnet],
  transports: {
    [mainnet.id]: fallback(
      [
        http('https://eth-mainnet.g.alchemy.com/v2/YOUR_KEY', { retryCount: 2 }),
        http('https://mainnet.infura.io/v3/YOUR_KEY', { retryCount: 1 }),
        webSocket('wss://rpc.quicknode.pro/YOUR_KEY'),
      ],
      { rank: true }
    ),
  },
})$escape$,
