INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a68fe492-8169-4871-bbd9-b2afff68073c',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi + IPFS Pinning — Pinata, web3.storage, and On-Chain CIDs via useWriteContract$escape$,
  $escape$IPFS pinning services ensure your NFT metadata stays retrievable — the CID you write on-chain via wagmi's `useWriteContract` is worthless if the content isn't pinned. The workflow is always: pin first, then write.

**Pinata** is the most battle-tested option. Use their REST API or `@pinata/sdk` to pin JSON metadata server-side (never expose your JWT client-side), then pass the returned `IpfsHash` as an `ipfs://` URI to your contract call.

**web3.storage** (w3up) uses UCAN-based auth and stores to both IPFS and Filecoin. It's more decentralized but requires the `@web3-storage/w3up-client` setup flow — heavier onboarding than Pinata.

**NFT.Storage** is largely legacy — its free tier depends on Protocol Labs funding and should not be used for new production builds.

**Self-hosted Kubo nodes** give full control via the HTTP API at `localhost:5001/api/v0/add`, but you bear the ops burden of availability and garbage collection.

In your wagmi component, the CID flows in as a prop or state after the async pin step, keeping your `writeContract` call clean and side-effect-free.$escape$,
  $escape$import { useWriteContract } from 'wagmi'
import type { Abi } from 'viem'

export function MintNFT({ abi, contractAddress }: { abi: Abi; contractAddress: `0x${string}` }) {
  const { writeContract, isPending } = useWriteContract()

  async function pinAndMint(metadata: Record<string, unknown>) {
    // Pin to Pinata server-side — JWT must never be exposed client-side
    const { cid } = await fetch('/api/pin-ipfs', {
      method: 'POST',
      body: JSON.stringify(metadata),
    }).then(r => r.json())

    writeContract({ address: contractAddress, abi, functionName: 'safeMint', args: [`ipfs://${cid}`] })
  }

  return <button disabled={isPending} onClick={() => pinAndMint({ name: 'ByteNFT #1' })}>Mint</button>
}$escape$,
  $escape$typescript$escape$,
