INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '091bb860-84b8-48a2-b62e-4fab9ccc32ac',
  '00000000-0000-0000-0000-000000000001',
  $escape$wagmi Event Indexing — Why getLogs Breaks in Production and What to Use Instead$escape$,
  $escape$wagmi's useWatchContractEvent is perfect for real-time event streaming, but it's a trap for historical data. Internally, it delegates to viem's watchContractEvent, which polls eth_getLogs — and every major RPC provider (Alchemy, Infura, QuickNode) caps that at 2,000–10,000 blocks per request. Try scanning a Uniswap V3 pool from deployment block and you'll exhaust rate limits or timeout before retrieving anything useful.

For production, pick one of two paths:

The Graph (subgraph): Write AssemblyScript mappings, deploy a subgraph, query via GraphQL. wagmi v2 ships TanStack Query as its data layer, so useQuery slots directly in — use it for historical state, useWatchContractEvent for live deltas only.

Custom indexer (Ponder, Envio): TypeScript-native, faster local iteration, full control over storage. Ponder exposes a REST/GraphQL API you wire straight into your wagmi frontend.

The production pattern: index all historical events externally → hydrate UI via useQuery → stream new events with useWatchContractEvent and trigger a refetch. Never paginate getLogs client-side — it doesn't scale past a few thousand blocks.$escape$,
  $escape$import { useWatchContractEvent } from 'wagmi'
import { useQuery } from '@tanstack/react-query'
import { erc20Abi } from 'viem'

function useTokenTransfers(address: `0x${string}`) {
  // Historical transfers from The Graph — NOT eth_getLogs
  const history = useQuery({
    queryKey: ['transfers', address],
    queryFn: () => fetchSubgraphTransfers(address),
  })

  // Only real-time deltas via wagmi
  useWatchContractEvent({
    address,
    abi: erc20Abi,
    eventName: 'Transfer',
    onLogs: () => history.refetch(),
  })

  return history
}$escape$,
  $escape$typescript$escape$,
